INSERT INTO email_send_logs ( hot_deal_id, user_id, recipient_email, title, content, status, retry_count ) SELECT #{hotDealId}, target.user_id, target.recipient_email, 'PENDING_TITLE', NULL, 'PENDING', 0 FROM (
SELECT #{target.userId} AS user_id, #{target.email} AS recipient_email FROM dual
) target WHERE NOT EXISTS ( SELECT 1 FROM email_send_logs existing WHERE existing.hot_deal_id = #{hotDealId} AND existing.user_id = target.user_id )
